# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os


def delete_uploaded_file(filename: str) -> dict:
    """
    Deletes a user's uploaded file from the 'uploads' directory based on the filename provided.

    Args:
        filename: The name of the file to delete.

    Returns:
        A dictionary with 'success' (bool) and 'message' (str) keys indicating the result.
    """
    if not filename:
        return {"success": False, "message": "No filename provided."}

    # Sanitize the filename to prevent directory traversal attacks
    safe_filename = os.path.basename(filename)

    if safe_filename != filename:
        return {
            "success": False,
            "message": "Invalid filename. Directory traversal is not allowed.",
        }

    uploads_dir = "uploads"
    file_path = os.path.join(uploads_dir, safe_filename)

    # Resolve to absolute path and verify it's still within the uploads directory
    abs_uploads_dir = os.path.abspath(uploads_dir)
    abs_file_path = os.path.abspath(file_path)

    if not abs_file_path.startswith(abs_uploads_dir + os.sep):
        return {
            "success": False,
            "message": "Invalid filename. Access outside uploads directory is not allowed.",
        }

    if not os.path.exists(abs_file_path):
        return {
            "success": False,
            "message": f"File '{safe_filename}' not found in uploads directory.",
        }

    if not os.path.isfile(abs_file_path):
        return {
            "success": False,
            "message": f"'{safe_filename}' is not a file.",
        }

    try:
        os.remove(abs_file_path)
        return {
            "success": True,
            "message": f"File '{safe_filename}' has been successfully deleted.",
        }
    except PermissionError:
        return {
            "success": False,
            "message": f"Permission denied: Unable to delete '{safe_filename}'.",
        }
    except OSError as e:
        return {
            "success": False,
            "message": f"Error deleting file '{safe_filename}': {str(e)}",
        }


if __name__ == "__main__":
    # Create uploads directory and a test file for demonstration
    os.makedirs("uploads", exist_ok=True)

